namespace Valora.Domain.Entities;

public sealed record MigrationSourceFile { public Guid Id { get; init; } public Guid? BatchId { get; init; } public string FileName { get; init; } = string.Empty; public string? ContentType { get; init; } public long SizeBytes { get; init; } public string Sha256 { get; init; } = string.Empty; public string? StoredPath { get; init; } public string Status { get; init; } = "registered"; public DateTime CreatedAt { get; init; } = DateTime.UtcNow; }
public sealed record MigrationRecord { public Guid Id { get; init; } public Guid BatchId { get; init; } public Guid? SourceFileId { get; init; } public string LegacyCollection { get; init; } = string.Empty; public string? LegacyId { get; init; } public string TargetEntity { get; init; } = string.Empty; public Guid? TargetId { get; init; } public string Action { get; init; } = "insert"; public string Status { get; init; } = "planned"; public string InputJson { get; init; } = "{}"; public string NormalizedJson { get; init; } = "{}"; public string? ErrorCode { get; init; } public string? ErrorMessage { get; init; } public DateTime CreatedAt { get; init; } = DateTime.UtcNow; public DateTime UpdatedAt { get; init; } = DateTime.UtcNow; }
public sealed record MigrationMapping { public Guid Id { get; init; } public Guid BatchId { get; init; } public string LegacyCollection { get; init; } = string.Empty; public string LegacyId { get; init; } = string.Empty; public string TargetEntity { get; init; } = string.Empty; public Guid TargetId { get; init; } public string MappingKey { get; init; } = string.Empty; public DateTime CreatedAt { get; init; } = DateTime.UtcNow; }
public sealed record MigrationConflict { public Guid Id { get; init; } public Guid BatchId { get; init; } public string LegacyCollection { get; init; } = string.Empty; public string? LegacyId { get; init; } public string TargetEntity { get; init; } = string.Empty; public Guid? TargetId { get; init; } public string ConflictType { get; init; } = string.Empty; public string Severity { get; init; } = "warning"; public string LegacyValueJson { get; init; } = "{}"; public string CurrentValueJson { get; init; } = "{}"; public string? Resolution { get; init; } public string? ResolvedBy { get; init; } public DateTime? ResolvedAt { get; init; } public DateTime CreatedAt { get; init; } = DateTime.UtcNow; }
public sealed record MigrationRollbackItem { public Guid Id { get; init; } public Guid BatchId { get; init; } public string TargetEntity { get; init; } = string.Empty; public Guid TargetId { get; init; } public string Operation { get; init; } = string.Empty; public string? BeforeJson { get; init; } public string? AfterJson { get; init; } public string? RollbackSql { get; init; } public string Status { get; init; } = "planned"; public DateTime CreatedAt { get; init; } = DateTime.UtcNow; public DateTime? RolledBackAt { get; init; } }
